import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import "../../styles/welcome.css";

export default function WelcomePage() {
  const navigate = useNavigate();
  const { user, logout } = useAuth();

  if (!user) return null;

  const goNext = () => {
    if (user.accountType !== "driver") {
      navigate("/driver/trips");
      return;
    }
    if (!user.carDetailsCompleted) {
      navigate("/driver/car-details");
      return;
    }
    if (!user.idDocumentUploaded) {
      navigate("/driver/verification-consent");
      return;
    }
    if (!user.faceVerified) {
      navigate("/driver/face-verification");
      return;
    }
    navigate("/driver/trips");
  };

  return (
    <div className="welcome-page">
      <div className="welcome-card">
        {/* Decorative arcs */}
        <div className="arc arc-left" />
        <div className="arc arc-right" />

        <div className="welcome-badge">SecureRide Driver Dashboard</div>

        <h1 className="welcome-title">
          Welcome, {user.fullNames?.split(" ")[0] || "Driver"} 👋
        </h1>

        <p className="welcome-subtitle">
          You’re signed in successfully. Complete your verification steps to start
          accepting trips safely and securely.
        </p>

        <div className="status-grid">
          <div className="status-item">
            <span>Account Type</span>
            <strong>{user.accountType || "—"}</strong>
          </div>

          <div className="status-item">
            <span>Car details</span>
            <strong>{user.carDetailsCompleted ? "✅ Complete" : "⏳ Pending"}</strong>
          </div>

          <div className="status-item">
            <span>ID upload</span>
            <strong>{user.idDocumentUploaded ? "✅ Uploaded" : "⏳ Pending"}</strong>
          </div>

          <div className="status-item">
            <span>Facial verification</span>
            <strong>{user.faceVerified ? "✅ Verified" : "⏳ Pending"}</strong>
          </div>
        </div>

        <div className="welcome-actions">
          <button className="welcome-btn primary" onClick={goNext}>
            Continue
          </button>
          <button className="welcome-btn ghost" onClick={logout}>
            Logout
          </button>
        </div>
      </div>
    </div>
  );
}
